class Solution {
public:
    int maxStability(int n, vector<vector<int>>& edges, int k) {
        vector<int> parent(n), rank(n, 1);
        for (int i = 0; i < n; i++) parent[i] = i;

        auto find = [&](int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        };

        auto unionSet = [&](int x, int y) {
            int rootx = find(x), rooty = find(y);
            if (rootx != rooty) {
                if (rank[rootx] > rank[rooty]) {
                    parent[rooty] = rootx;
                } else if (rank[rootx] < rank[rooty]) {
                    parent[rootx] = rooty;
                } else {
                    parent[rooty] = rootx;
                    rank[rootx]++;
                }
            }
        };

        sort(edges.begin(), edges.end(), [](vector<int>& a, vector<int>& b) {
            return a[2] < b[2];
        });

        int mustEdges = 0, optionalEdges = 0, minStrength = INT_MAX;
        for (auto& edge : edges) {
            if (edge[3] == 1) {
                mustEdges++;
                unionSet(edge[0], edge[1]);
                minStrength = min(minStrength, edge[2]);
            }
        }

        if (mustEdges > n - 1 || find(0) != find(n - 1)) return -1;

        for (auto& edge : edges) {
            if (edge[3] == 0) {
                if (find(edge[0]) != find(edge[1])) {
                    unionSet(edge[0], edge[1]);
                    optionalEdges++;
                    minStrength = min(minStrength, edge[2]);
                }
            }
        }

        if (optionalEdges + mustEdges < n - 1) return -1;

        int low = 1, high = 1e5;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            int upgrades = 0;
            parent = vector<int>(n);
            rank = vector<int>(n, 1);
            for (int i = 0; i < n; i++) parent[i] = i;

            for (auto& edge : edges) {
                if (edge[3] == 1) {
                    unionSet(edge[0], edge[1]);
                }
            }

            for (auto& edge : edges) {
                if (edge[3] == 0) {
                    if (edge[2] < mid && upgrades < k) {
                        upgrades++;
                        edge[2] *= 2;
                    }
                    if (edge[2] >= mid && find(edge[0]) != find(edge[1])) {
                        unionSet(edge[0], edge[1]);
                    }
                }
            }

            if (find(0) == find(n - 1)) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }

        return high;
    }
};
